const DEMO_OPTION_ROWS: Array<{ key: keyof DemoSeedOptions; label: string; description: string }> = [
  { key: "clipboard", label: "Clipboard demo data", description: "History, snippets, slots, and a multi-copy group." },
  { key: "vault", label: "Vault demo documents", description: "Work Permit / Passport / Lease / Resume with OCR text for Smart Lookup." },
  { key: "finance", label: "Finance demo data", description: "Personal + Business profiles, transactions, recurring, receipts." },
  { key: "journalCalendar", label: "Journal / Calendar demo data", description: "Entries (incl. ‘Call Tim tomorrow at 3’) and events." },
  { key: "captureFinder", label: "Capture / Finder demo data", description: "Inbox captures and item locations." },
  { key: "timetable", label: "Timetable demo data", description: "Weekly blocks incl. current/next based on the time now." },
  { key: "news", label: "News cached demo", description: "Cached AI/Tech/Finance/Sports/Canada headlines (no network)." },
  { key: "devDeck", label: "Dev / Deck demo data", description: "A safe demo project and demo routines (commands not run)." }
];

function DemoDataSection({ onAction, onRefresh }: { onAction: (actionId: string, source?: string, params?: unknown) => Promise<unknown>; onRefresh: () => Promise<void> }) {
  const [options, setOptions] = useState<DemoSeedOptions>({ replaceExisting: true, clipboard: true, vault: true, finance: true, journalCalendar: true, captureFinder: true, timetable: true, news: true, devDeck: true, secureVault: false });
  const [preview, setPreview] = useState<DemoPreview | null>(null);
  const [results, setResults] = useState<DemoModuleResult[] | null>(null);
  const [busy, setBusy] = useState<null | "preview" | "seed" | "clear">(null);
  const [message, setMessage] = useState("");
  const [seededAt, setSeededAt] = useState<string | null>(null);

  const loadState = useCallback(async () => {
    try { const s = await getBridge().getDemoState(); setSeededAt(s?.seededAt ?? null); } catch { /* ignore */ }
  }, []);
  useEffect(() => { void loadState(); }, [loadState]);

  const setOption = (key: keyof DemoSeedOptions, value: boolean) => { setOptions((current) => ({ ...current, [key]: value })); setPreview(null); };

  const doPreview = async () => {
    setBusy("preview"); setMessage("");
    try {
      const res = (await onAction("demo.preview_seed", "module_ui", { options })) as { ok?: boolean; preview?: DemoPreview; error?: string } | undefined;
      if (res?.ok && res.preview) { setPreview(res.preview); setResults(null); } else { setMessage(res?.error ?? "Could not build a preview."); }
    } finally { setBusy(null); }
  };

  const doSeed = async () => {
    setBusy("seed"); setMessage("");
    try {
      const res = (await onAction("demo.seed", "module_ui", { options })) as { ok?: boolean; results?: DemoModuleResult[]; error?: string } | undefined;
      if (res && Array.isArray(res.results)) { setResults(res.results); setPreview(null); await loadState(); await onRefresh(); } else { setMessage(res?.error ?? "Seeding failed."); }
    } finally { setBusy(null); }
  };

  const doClear = async () => {
    setBusy("clear"); setMessage("");
    try {
      const res = (await onAction("demo.clear", "module_ui", {})) as { ok?: boolean; results?: DemoModuleResult[]; totalRemoved?: number; error?: string } | undefined;
      if (res && Array.isArray(res.results)) { setResults(res.results); setPreview(null); await loadState(); await onRefresh(); } else { setMessage(res?.error ?? "Clearing failed."); }
    } finally { setBusy(null); }
  };

  return (
    <GlassCard hover={false}>
      <SectionTitle>Demo Data</SectionTitle>
      <p style={{ opacity: 0.75, fontSize: 13, marginTop: -4 }}>
        Fill DexNest with safe, clearly-marked fake data (<span className="technical">demoData=true</span>, <span className="technical">seedId=default_demo_seed</span>) to test every module, then remove it cleanly. No real personal data, API keys, or credentials are seeded; Weather and External Devices are left as you configured them.
      </p>
      {seededAt && <p style={{ fontSize: 12, opacity: 0.7, marginTop: 6 }}>Demo data last seeded: <strong>{formatLocalDateTime(seededAt)}</strong></p>}

      <div className="settings-list" style={{ marginTop: 10 }}>
        <label className="settings-row" style={{ cursor: "pointer", gap: 12 }}>
          <input type="checkbox" checked={options.replaceExisting} onChange={(e) => setOption("replaceExisting", e.target.checked)} />
          <span style={{ display: "flex", flexDirection: "column", gap: 2 }}>
            <strong>Replace existing demo data before seeding</strong>
            <span style={{ opacity: 0.7, fontSize: 12 }}>Removes prior demo records first so re-seeding never duplicates. Real data is untouched.</span>
          </span>
        </label>
        {DEMO_OPTION_ROWS.map((row) => (
          <label key={row.key} className="settings-row" style={{ cursor: "pointer", gap: 12 }}>
            <input type="checkbox" checked={options[row.key]} onChange={(e) => setOption(row.key, e.target.checked)} />
            <span style={{ display: "flex", flexDirection: "column", gap: 2 }}>
              <strong>{row.label}</strong>
              <span style={{ opacity: 0.7, fontSize: 12 }}>{row.description}</span>
            </span>
          </label>
        ))}
        <label className="settings-row" style={{ cursor: "pointer", gap: 12 }}>
          <input type="checkbox" checked={options.secureVault} onChange={(e) => setOption("secureVault", e.target.checked)} />
          <span style={{ display: "flex", flexDirection: "column", gap: 2 }}>
            <strong style={{ display: "flex", alignItems: "center", gap: 6 }}><ShieldAlert size={13} color="#FB4D6A" /> Secure Vault demo item (off by default)</strong>
            <span style={{ opacity: 0.7, fontSize: 12 }}>Adds one obviously-fake login. Requires Secure Vault to be unlocked.</span>
          </span>
        </label>
      </div>

      <p style={{ opacity: 0.55, fontSize: 11, marginTop: 8 }}>Command/Audit, Drop, Tools, Heatmap, Utilities, and a tiny demo Backup are always included.</p>

      {message && <p style={{ color: "#FB4D6A", fontSize: 12 }}>{message}</p>}

      {preview && (
        <div className="settings-row" style={{ flexDirection: "column", alignItems: "flex-start", gap: 4, marginTop: 10, borderLeft: "3px solid #22D3EE", paddingLeft: 10 }}>
          <strong>Preview — {preview.totalRecords} record(s), {preview.totalFiles} demo file(s)</strong>
          {preview.items.map((item) => (
            <span key={item.module} className="technical" style={{ fontSize: 11, opacity: 0.8 }}>{item.module}: {item.records} record(s){item.files ? `, ${item.files} file(s)` : ""}</span>
          ))}
          <span style={{ fontSize: 11, opacity: 0.6, marginTop: 4 }}>Demo files: {preview.demoFilesRoot}</span>
          {preview.notes.map((note) => <span key={note} style={{ fontSize: 11, opacity: 0.6 }}>• {note}</span>)}
        </div>
      )}

      {results && (
        <div className="settings-row" style={{ flexDirection: "column", alignItems: "flex-start", gap: 4, marginTop: 10, borderLeft: `3px solid ${results.some((r) => r.status === "failed") ? "#FB4D6A" : "#4ADE80"}`, paddingLeft: 10 }}>
          <strong style={{ display: "flex", alignItems: "center", gap: 6 }}>
            {results.some((r) => r.status === "failed") ? <AlertTriangle size={15} color="#FB4D6A" /> : <CheckCircle2 size={15} color="#4ADE80" />}
            {results.some((r) => r.status === "cleared") ? "Demo data cleared" : "Demo data seeded"}
          </strong>
          {results.map((r) => (
            <span key={r.module} className="technical" style={{ fontSize: 11, opacity: r.status === "failed" ? 1 : 0.78, color: r.status === "failed" ? "#FB4D6A" : undefined }}>
              {r.status === "failed" ? "✗" : r.status === "skipped" ? "—" : "✓"} {r.label}: {r.records} record(s){r.files ? `, ${r.files} file(s)` : ""}{r.note ? ` — ${r.note}` : ""}
            </span>
          ))}
        </div>
      )}

      <div style={{ display: "flex", gap: 8, marginTop: 12, flexWrap: "wrap" }}>
        <button type="button" className="ghost-button" onClick={doPreview} disabled={busy !== null}>{busy === "preview" ? "Building…" : "Preview Demo Data"}</button>
        <button type="button" className="primary-button" onClick={doSeed} disabled={busy !== null}>{busy === "seed" ? "Seeding…" : "Seed Demo Data"}</button>
        <button type="button" className="ghost-button" onClick={doClear} disabled={busy !== null}>{busy === "clear" ? "Clearing…" : "Clear Demo Data"}</button>
      </div>

      {(busy === "seed" || busy === "clear") && (
        <div style={{ position: "fixed", inset: 0, zIndex: 9999, background: "rgba(5,7,15,0.85)", backdropFilter: "blur(6px)", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 16 }}>
          <RefreshCw size={48} color="#22D3EE" className="animate-spin-slow" />
          <strong style={{ fontSize: 18 }}>{busy === "seed" ? "Seeding demo data across modules…" : "Clearing demo data…"}</strong>
          <span style={{ opacity: 0.7, fontSize: 13 }}>Please wait — do not close DexNest.</span>
        </div>
      )}
    </GlassCard>
  );
}

function DataManagementSection({
  onAction,
  onRefresh
}: {
  onAction: (actionId: string, source?: string, params?: unknown) => Promise<unknown>;
  onRefresh: () => Promise<void>;
}) {
  const [state, setState] = useState<DataManagementState | null>(null);
  const [selected, setSelected] = useState<Set<string>>(new Set());
  const [preview, setPreview] = useState<DataManagementPreview | null>(null);
  const [confirmText, setConfirmText] = useState("");
  const [stage, setStage] = useState<"select" | "preview">("select");
  const [deleting, setDeleting] = useState(false);
  const [result, setResult] = useState<DataManagementDeleteResult | null>(null);
  const [message, setMessage] = useState("");
  const [busy, setBusy] = useState(false);

  const load = useCallback(async () => {
    try {
      setState(await getBridge().getDataManagementState());
    } catch {
      /* ignore */
    }
  }, []);

  useEffect(() => {
    void load();
  }, [load]);

  const categories = state?.categories ?? [];
  const standard = categories.filter((category) => !category.sensitive);
  const sensitive = categories.filter((category) => category.sensitive);
  const lastDeletion = state?.lastDeletion;

  const toggle = (id: string) => {
    setSelected((prev) => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
    setMessage("");
  };

  const selectAll = () => {
    setSelected(new Set(categories.map((category) => category.id)));
    setMessage("");
  };

  const clearAll = () => {
    setSelected(new Set());
    setMessage("");
  };

  const doPreview = async () => {
    setBusy(true);
    setMessage("");
    try {
      const res = (await onAction("system.data.preview_delete", "module_ui", { categoryIds: [...selected] })) as
        | { ok?: boolean; preview?: DataManagementPreview; error?: string }
        | undefined;
      if (res?.ok && res.preview) {
        setPreview(res.preview);
        setConfirmText("");
        setResult(null);
        setStage("preview");
      } else {
        setMessage(res?.error ?? "Could not build a preview.");
      }
    } finally {
      setBusy(false);
    }
  };

  const doDelete = async (createBackupFirst: boolean) => {
    setDeleting(true);
    setMessage("");
    try {
      const res = (await onAction("system.data.execute_delete", "module_ui", {
        categoryIds: [...selected],
        confirmText,
        createBackupFirst,
        confirmedDangerous: true
      })) as (DataManagementDeleteResult & { error?: string }) | undefined;
      if (res && Array.isArray(res.results)) {
        setResult(res);
        setStage("select");
        setSelected(new Set());
        setPreview(null);
        setConfirmText("");
        await load();
        await onRefresh();
      } else {
        setMessage(res?.error ?? "Deletion failed.");
      }
    } finally {
      setDeleting(false);
    }
  };

  const renderCategoryRow = (category: DataManagementCategoryState) => (
    <label key={category.id} className="settings-row" style={{ alignItems: "flex-start", cursor: "pointer", gap: 12 }}>
      <input type="checkbox" checked={selected.has(category.id)} onChange={() => toggle(category.id)} style={{ marginTop: 4 }} />
      <span style={{ display: "flex", flexDirection: "column", gap: 2 }}>
        <strong style={{ display: "flex", alignItems: "center", gap: 6 }}>
          {category.label}
          {category.sensitive && <ShieldAlert size={13} color="#FB4D6A" />}
        </strong>
        <span style={{ opacity: 0.7, fontSize: 12 }}>{category.description}</span>
        <span className="technical" style={{ opacity: 0.6, fontSize: 11 }}>
          {category.records} record{category.records === 1 ? "" : "s"}
          {category.files > 0 ? ` · ${category.files} file${category.files === 1 ? "" : "s"}` : ""}
        </span>
      </span>
    </label>
  );

  return (
    <GlassCard hover={false}>
      <SectionTitle>Data Management</SectionTitle>
      <p style={{ opacity: 0.75, fontSize: 13, marginTop: -4 }}>
        Permanently delete selected DexNest data with an optional backup first. App code, schemas, the database structure,
        sidecars, and package files are never touched — only DexNest-managed records and files are removed, and empty
        defaults are recreated so the app stays usable.
      </p>

      {lastDeletion?.lastDeletionAt && (
        <div className="settings-row" style={{ flexDirection: "column", alignItems: "flex-start", gap: 2, marginTop: 8 }}>
          <span style={{ fontSize: 12, opacity: 0.7 }}>Last deletion</span>
          <strong style={{ fontSize: 12 }}>
            {formatLocalDateTime(lastDeletion.lastDeletionAt)} · {lastDeletion.status ?? "unknown"} · backup:{" "}
            {lastDeletion.backupCreated ? lastDeletion.backupFileName ?? "yes" : "none"}
          </strong>
          {lastDeletion.categoriesCleared.length > 0 && (
            <span style={{ fontSize: 11, opacity: 0.6 }}>Cleared: {lastDeletion.categoriesCleared.join(", ")}</span>
          )}
        </div>
      )}

      {result && (
        <div
          className="settings-row"
          style={{
            flexDirection: "column",
            alignItems: "flex-start",
            gap: 6,
            marginTop: 10,
            borderLeft: `3px solid ${result.status === "failed" ? "#FB4D6A" : result.status === "partial" ? "#F59E0B" : "#4ADE80"}`,
            paddingLeft: 10
          }}
        >
          <strong style={{ display: "flex", alignItems: "center", gap: 6 }}>
            {result.status === "failed" ? <AlertTriangle size={15} color="#FB4D6A" /> : <CheckCircle2 size={15} color="#4ADE80" />}
            Deletion {result.status}
          </strong>
          {result.backupCreated && <span style={{ fontSize: 12, opacity: 0.8 }}>Backup created: {result.backupFileName}</span>}
          {result.backupError && <span style={{ fontSize: 12, color: "#FB4D6A" }}>Backup: {result.backupError}</span>}
          {result.results.map((entry) => (
            <span key={entry.id} className="technical" style={{ fontSize: 11, opacity: entry.ok ? 0.75 : 1, color: entry.ok ? undefined : "#FB4D6A" }}>
              {entry.ok ? "✓" : "✗"} {entry.label}: {entry.recordsCleared} record(s){entry.filesDeleted ? `, ${entry.filesDeleted} file(s)` : ""}
              {entry.error ? ` — ${entry.error}` : ""}
            </span>
          ))}
        </div>
      )}

      {stage === "select" && (
        <>
          <div style={{ display: "flex", gap: 8, margin: "12px 0", flexWrap: "wrap" }}>
            <button type="button" className="ghost-button" onClick={selectAll}>Select all (delete all data)</button>
            <button type="button" className="ghost-button" onClick={clearAll} disabled={selected.size === 0}>Clear selection</button>
            <span style={{ marginLeft: "auto", alignSelf: "center", fontSize: 12, opacity: 0.7 }}>{selected.size} selected</span>
          </div>

          <SectionTitle>Standard categories</SectionTitle>
          <div className="settings-list">{standard.map(renderCategoryRow)}</div>

          <SectionTitle>
            <span style={{ display: "inline-flex", alignItems: "center", gap: 6 }}>
              <ShieldAlert size={15} color="#FB4D6A" /> Sensitive categories
            </span>
          </SectionTitle>
          <p style={{ opacity: 0.7, fontSize: 12, marginTop: -4 }}>
            These delete real managed files, credentials, backups, or the Secure Vault. Select each one explicitly.
          </p>
          <div className="settings-list">{sensitive.map(renderCategoryRow)}</div>

          {message && <p style={{ color: "#FB4D6A", fontSize: 12 }}>{message}</p>}

          <div style={{ marginTop: 12 }}>
            <button type="button" className="primary-button" onClick={doPreview} disabled={selected.size === 0 || busy}>
              {busy ? "Building preview…" : "Preview deletion"}
            </button>
          </div>
        </>
      )}

      {stage === "preview" && preview && (
        <div style={{ marginTop: 12 }}>
          <SectionTitle>Preview deletion</SectionTitle>
          <p style={{ fontSize: 13, opacity: 0.85 }}>
            This will permanently delete <strong>{preview.totalRecords}</strong> record(s) and{" "}
            <strong>{preview.totalFiles}</strong> managed file(s) across {preview.items.length} categor
            {preview.items.length === 1 ? "y" : "ies"}. Counts and folders only — no private content is shown.
          </p>
          <div className="settings-list">
            {preview.items.map((item) => (
              <div className="settings-row" key={item.id} style={{ flexDirection: "column", alignItems: "flex-start", gap: 2 }}>
                <strong style={{ display: "flex", alignItems: "center", gap: 6 }}>
                  {item.label}
                  {item.sensitive && <ShieldAlert size={13} color="#FB4D6A" />}
                </strong>
                <span className="technical" style={{ fontSize: 11, opacity: 0.7 }}>
                  {item.records} record(s){item.files ? `, ${item.files} file(s)` : ""}
                </span>
                {item.folders.map((folder) => (
                  <span key={folder} className="technical" style={{ fontSize: 11, opacity: 0.55 }}>{folder}</span>
                ))}
              </div>
            ))}
          </div>

          <div className="settings-row" style={{ flexDirection: "column", alignItems: "flex-start", gap: 6, marginTop: 10 }}>
            <span style={{ fontSize: 13 }}>
              Type <strong>DELETE</strong> to confirm:
            </span>
            <input
              type="text"
              value={confirmText}
              onChange={(event) => setConfirmText(event.target.value)}
              placeholder="DELETE"
              spellCheck={false}
              autoComplete="off"
              style={{ width: 200 }}
            />
          </div>

          {message && <p style={{ color: "#FB4D6A", fontSize: 12 }}>{message}</p>}

          <div style={{ display: "flex", gap: 8, marginTop: 12, flexWrap: "wrap" }}>
            <button type="button" className="primary-button" disabled={confirmText !== "DELETE" || deleting} onClick={() => doDelete(true)}>
              Create backup first, then delete
            </button>
            <button type="button" className="ghost-button" disabled={confirmText !== "DELETE" || deleting} onClick={() => doDelete(false)}>
              Continue without backup
            </button>
            <button type="button" className="ghost-button" disabled={deleting} onClick={() => { setStage("select"); setMessage(""); }}>
              Back
            </button>
          </div>
        </div>
      )}

      {deleting && (
        <div
          style={{
            position: "fixed",
            inset: 0,
            zIndex: 9999,
            background: "rgba(5, 7, 15, 0.85)",
            backdropFilter: "blur(6px)",
            display: "flex",
            flexDirection: "column",
            alignItems: "center",
            justifyContent: "center",
            gap: 16
          }}
        >
          <RefreshCw size={48} color="#22D3EE" className="animate-spin-slow" />
          <strong style={{ fontSize: 18 }}>Deleting selected DexNest data…</strong>
          <span style={{ opacity: 0.7, fontSize: 13 }}>Please wait — do not close DexNest.</span>
        </div>
      )}
    </GlassCard>
  );
}

function Panel({ title, children }: { title: string; children: React.ReactNode }) {
  return (
    <article className="panel">
      <h3>{title}</h3>
      <div className="panel__body">{children}</div>
    </article>
  );
}

// Exposed for the headless voice-command validation harness (scripts/dev tooling
// and tests). These are pure functions/data with no DOM dependency.
export { validateVoiceCapabilities, voiceValidationBroken, getVoiceCapabilityGroups, defaultVoiceWorkflowSettings };

// Browser-only bootstrap. Guarded so the module can be imported in a headless
// (Node) context — e.g. the voice-command validation harness — without trying to
// mount React or touch the DOM. In the real renderer `document` always exists.
if (typeof document !== "undefined") {
  try {
    document.documentElement.setAttribute("data-reduce-motion", localStorage.getItem("dexnest:reduceMotion") === "1" ? "true" : "false");
    document.documentElement.setAttribute("data-grain", localStorage.getItem("dexnest:grain") === "0" ? "false" : "true");
  } catch { /* ignore */ }

  const root = document.getElementById("root");

  if (!root) {
    throw new Error("DexNest root element was not found.");
  }

  createRoot(root).render(
    <React.StrictMode>
      <DexNestApp />
    </React.StrictMode>
  );
}
